from __future__ import annotations

import datetime as dt
import random
from collections.abc import Sequence
from typing import TypeVar

T = TypeVar("T")


class Rng:
    """Thin convenience wrapper over random.Random with id/date helpers."""

    def __init__(self, seed: int) -> None:
        self._r = random.Random(seed)

    # --- primitives -------------------------------------------------------
    def choice(self, seq: Sequence[T]) -> T:
        return self._r.choice(seq)

    def choices(self, seq: Sequence[T], weights: Sequence[float], k: int = 1) -> list[T]:
        return self._r.choices(seq, weights=weights, k=k)

    def weighted(self, seq: Sequence[T], weights: Sequence[float]) -> T:
        return self._r.choices(seq, weights=weights, k=1)[0]

    def randint(self, lo: int, hi: int) -> int:
        return self._r.randint(lo, hi)

    def uniform(self, lo: float, hi: float) -> float:
        return self._r.uniform(lo, hi)

    def money(self, lo: float, hi: float) -> float:
        return round(self._r.uniform(lo, hi), 2)

    def chance(self, p: float) -> bool:
        return self._r.random() < p

    def sample(self, seq: Sequence[T], k: int) -> list[T]:
        return self._r.sample(list(seq), k)

    def shuffle(self, seq: list[T]) -> None:
        self._r.shuffle(seq)

    # --- ids --------------------------------------------------------------
    def id_pool(self, prefix: str, n: int, width: int = 6) -> list[str]:
        """A stable, ordered pool of human-readable ids (e.g. SKU-000001)."""
        return [f"{prefix}-{i:0{width}d}" for i in range(1, n + 1)]

    # --- dates ------------------------------------------------------------
    def datetime_between(self, start: dt.datetime, end: dt.datetime) -> dt.datetime:
        span = int((end - start).total_seconds())
        return start + dt.timedelta(seconds=self._r.randint(0, max(span, 1)))

