"""Persisted harness state for incremental `tick` generation (§2a).

The §2 backfill is stateless one-shot. Recurring ticks need continuity *across*
runs: the same master pools, climbing id sequences (no `order_number` collisions),
and open shipments (a tracking_number created on an earlier tick gets its next
lifecycle event on a later tick). That continuity lives here.

Storage is behind a **`StateBackend` seam** so the same state works whether ticks
run locally (filesystem) or as the ephemeral **Container Apps Job** (ADLS blob —
local disk doesn't survive between Job runs). Pick the backend by URI:
  local path            -> LocalStateBackend   (e.g. ./state)
  adls://<acct>/<fs>/<p> -> AdlsStateBackend    (e.g. adls://dataqhX/landing/state)

Logical contents (relative names the backend stores):
  state.json              counters, open_shipments, last_inventory_date, batch_counter
  masters/<name>.parquet  products, customers, locations, channels, promotions
"""

from __future__ import annotations

import json
from abc import ABC, abstractmethod
from dataclasses import asdict, dataclass, field
from io import BytesIO
from pathlib import Path

import pandas as pd

MASTER_NAMES = ("products", "customers", "locations", "channels", "promotions")
STATE_FILE = "state.json"


# --- state record ----------------------------------------------------------


@dataclass
class HarnessState:
    seed: int
    tier: str
    created_at: str
    batch_counter: int = 0
    counters: dict[str, int] = field(
        default_factory=lambda: {"order": 0, "line": 0, "return": 0, "feedback": 0}
    )
    last_inventory_date: str | None = None
    open_shipments: list[dict] = field(default_factory=list)

    @classmethod
    def from_dict(cls, d: dict) -> HarnessState:
        return cls(**d)


# --- backend seam ----------------------------------------------------------


class StateBackend(ABC):
    """Byte storage for state.json + masters/*.parquet. Local FS or ADLS blob."""

    @abstractmethod
    def exists(self, rel: str) -> bool: ...

    @abstractmethod
    def read_bytes(self, rel: str) -> bytes: ...

    @abstractmethod
    def write_bytes(self, rel: str, data: bytes) -> None: ...


class LocalStateBackend(StateBackend):
    def __init__(self, root: str) -> None:
        self.root = Path(root)

    def _p(self, rel: str) -> Path:
        return self.root / rel

    def exists(self, rel: str) -> bool:
        return self._p(rel).exists()

    def read_bytes(self, rel: str) -> bytes:
        return self._p(rel).read_bytes()

    def write_bytes(self, rel: str, data: bytes) -> None:
        p = self._p(rel)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(data)


class AdlsStateBackend(StateBackend):
    """ADLS Gen2 blob backend for the ephemeral Container Apps Job.

    Auth via DefaultAzureCredential — managed identity in the Job, `az login` (or
    AZURE_* env SP) locally. azure-* libs are imported lazily so the package runs
    with the local backend even when they aren't installed.
    """

    def __init__(self, account: str, filesystem: str, prefix: str) -> None:
        from azure.identity import DefaultAzureCredential
        from azure.storage.filedatalake import DataLakeServiceClient

        self.prefix = prefix.strip("/")
        svc = DataLakeServiceClient(
            account_url=f"https://{account}.dfs.core.windows.net",
            credential=DefaultAzureCredential(),
        )
        self._fs = svc.get_file_system_client(filesystem)

    def _path(self, rel: str) -> str:
        return f"{self.prefix}/{rel}" if self.prefix else rel

    def exists(self, rel: str) -> bool:
        return self._fs.get_file_client(self._path(rel)).exists()

    def read_bytes(self, rel: str) -> bytes:
        return self._fs.get_file_client(self._path(rel)).download_file().readall()

    def write_bytes(self, rel: str, data: bytes) -> None:
        self._fs.get_file_client(self._path(rel)).upload_data(data, overwrite=True)


def make_backend(uri: str) -> StateBackend:
    """`adls://<account>/<filesystem>/<prefix...>` -> ADLS; anything else -> local path."""
    if uri.startswith("adls://"):
        rest = uri[len("adls://") :]
        parts = rest.split("/", 2)
        if len(parts) < 2:
            raise ValueError(
                f"bad adls uri {uri!r}; expected adls://<account>/<filesystem>[/<prefix>]"
            )
        account, filesystem = parts[0], parts[1]
        prefix = parts[2] if len(parts) == 3 else ""
        return AdlsStateBackend(account, filesystem, prefix)
    return LocalStateBackend(uri)


# --- state + masters IO (backend-agnostic) ---------------------------------


def state_exists(backend: StateBackend) -> bool:
    return backend.exists(STATE_FILE)


def save_state(backend: StateBackend, state: HarnessState) -> None:
    backend.write_bytes(
        STATE_FILE, json.dumps(asdict(state), indent=2, default=str).encode()
    )


def load_state(backend: StateBackend) -> HarnessState:
    if not state_exists(backend):
        raise FileNotFoundError("no state found — run `python -m mockdata init` first")
    return HarnessState.from_dict(json.loads(backend.read_bytes(STATE_FILE)))


def save_masters(backend: StateBackend, masters: dict[str, pd.DataFrame]) -> None:
    for name in MASTER_NAMES:
        buf = BytesIO()
        masters[name].to_parquet(buf, index=False)
        backend.write_bytes(f"masters/{name}.parquet", buf.getvalue())


def load_masters(backend: StateBackend) -> dict[str, pd.DataFrame]:
    return {
        name: pd.read_parquet(BytesIO(backend.read_bytes(f"masters/{name}.parquet")))
        for name in MASTER_NAMES
    }

