        return self._fs.get_file_client(self._path(rel)).exists()

    def read_bytes(self, rel: str) -> bytes:
        return self._fs.get_file_client(self._path(rel)).download_file().readall()

    def write_bytes(self, rel: str, data: bytes) -> None:
        self._fs.get_file_client(self._path(rel)).upload_data(data, overwrite=True)


def make_backend(uri: str) -> StateBackend:
    """`adls://<account>/<filesystem>/<prefix...>` -> ADLS; anything else -> local path."""
    if uri.startswith("adls://"):
        rest = uri[len("adls://") :]
        parts = rest.split("/", 2)
        if len(parts) < 2:
            raise ValueError(
                f"bad adls uri {uri!r}; expected adls://<account>/<filesystem>[/<prefix>]"
            )
        account, filesystem = parts[0], parts[1]
        prefix = parts[2] if len(parts) == 3 else ""
        return AdlsStateBackend(account, filesystem, prefix)
    return LocalStateBackend(uri)


# --- state + masters IO (backend-agnostic) ---------------------------------


def state_exists(backend: StateBackend) -> bool:
    return backend.exists(STATE_FILE)


def save_state(backend: StateBackend, state: HarnessState) -> None:
    backend.write_bytes(
        STATE_FILE, json.dumps(asdict(state), indent=2, default=str).encode()
    )


def load_state(backend: StateBackend) -> HarnessState:
    if not state_exists(backend):
        raise FileNotFoundError("no state found — run `python -m mockdata init` first")
    return HarnessState.from_dict(json.loads(backend.read_bytes(STATE_FILE)))


def save_masters(backend: StateBackend, masters: dict[str, pd.DataFrame]) -> None:
    for name in MASTER_NAMES:
        buf = BytesIO()
        masters[name].to_parquet(buf, index=False)
        backend.write_bytes(f"masters/{name}.parquet", buf.getvalue())


def load_masters(backend: StateBackend) -> dict[str, pd.DataFrame]:
    return {
        name: pd.read_parquet(BytesIO(backend.read_bytes(f"masters/{name}.parquet")))
        for name in MASTER_NAMES
    }

